1948→/* Diffs (Pierre) theme bridge — v1.1.7
1949→   All theming goes here on the host element. CSS custom properties inherit
1950→   into Shadow DOM, so the library picks these up without unsafeCSS hacks.
1951→
1952→   Use --diffs-*-override variables for colors the library explicitly exposes.
1953→   Use --diffs-fg/--diffs-bg for base foreground/background (v1.1.7+).
1954→   Never use !important — the override variables are the intended cascade path. */
1955→diffs-container.diffs-theme {
1956→  padding: 0;
1957→  margin: 0;
1958→  letter-spacing: 0em;
1959→
1960→  /* Base colors — controls pre/code background + default text color */
1961→  --diffs-fg: var(--foreground);
1962→  --diffs-bg: var(--background);
1963→  --diffs-light-bg: var(--background);

 1→/**
 2→ * Subagent Message List
 3→ *
 4→ * Compact renderer for subagent child messages.
 5→ * Renders content blocks (tool calls, text, thinking) from subagent messages
 6→ * using the existing BlockRenderer, with tighter spacing and indentation.
 7→ */
 8→
 9→import { memo, useMemo, Fragment } from "react";
10→import type { Message } from "@/shared/types";
11→import type { ContentBlock } from "@/features/session/types";
12→import { isToolResultBlock, isToolUseBlock } from "@/features/session/types";
13→import { useSession } from "../../context";
14→
15→interface SubagentMessageListProps {
16→  messages: Message[];
17→}
18→
19→export const SubagentMessageList = memo(function SubagentMessageList({
20→  messages,
21→}: SubagentMessageListProps) {
22→  const { parseContent, renderBlock } = useSession();
23→
24→  // Parse all messages into content blocks, filtering out tool_result-only and empty messages
25→  const renderableBlocks = useMemo(() => {
26→    const blocks: Array<{ block: ContentBlock | string; key: string }> = [];
27→
28→    messages.forEach((message) => {
29→      const contentBlocks = parseContent(message.content);
30→      if (!Array.isArray(contentBlocks)) return;
31→
32→      // Skip messages that are only tool_results (they link to tool_use via toolResultMap)
33→      const onlyToolResults =
34→        contentBlocks.length > 0 &&
35→        contentBlocks.every((b: ContentBlock | string) => isToolResultBlock(b));
36→      if (onlyToolResults) return;
37→
38→      contentBlocks.forEach((block: ContentBlock | string, index: number) => {
39→        // Skip standalone tool_result blocks (they render inline with tool_use)
40→        if (isToolResultBlock(block)) return;
41→
42→        const key = isToolUseBlock(block) ? block.id : `${message.id}:${index}`;
43→
44→        blocks.push({ block, key });
45→      });
46→    });
47→
48→    return blocks;
49→  }, [messages, parseContent]);
50→
51→  if (renderableBlocks.length === 0) return null;
52→
53→  return (
54→    <div className="border-border/30 flex flex-col gap-0.5 border-l pl-3">
55→      {renderableBlocks.map(({ block, key }, index) => (
56→        <Fragment key={key}>{renderBlock(block, index, "assistant", false)}</Fragment>
57→      ))}
58→    </div>
59→  );
60→});
