  1→/**
  2→ * Message Item (Refactored)
  3→ *
  4→ * Uses the new registry pattern with BlockRenderer for extensible content rendering.
  5→ * Automatically imports and registers all tool renderers.
  6→ */
  7→
  8→import type { Message } from "@/shared/types";
  9→import type { ContentBlock } from "@/features/session/types";
 10→import { isImageBlock, isTextBlock, isToolUseBlock } from "@/features/session/types";
 11→import { BlockRenderer, ToolGroupBlock } from "./blocks";
 12→import { groupToolStreaks, type GroupedItem } from "./utils/groupTools";
 13→import { match } from "ts-pattern";
 14→
 15→import { cn } from "@/shared/lib/utils";
 16→import { Copy, ChevronDown, ChevronUp } from "lucide-react";
 17→import { ActionButton } from "./ActionButton";
 18→import { useCopyToClipboard } from "@/shared/hooks";
 19→import { useSession } from "../context";
 20→import { useMemo, memo, useState, useRef, useEffect } from "react";
 21→import { motion } from "framer-motion";
 22→
 23→// Import tool registry initialization (registers all tools)
 24→import "./tools/registerTools";
 25→
 26→const COLLAPSE_MAX_HEIGHT = 144;
 27→
 28→type ParsedContent = (ContentBlock | string)[] | string;
 29→
 30→interface MessageItemProps {
 31→  message: Message;
 32→  isLatestAssistant?: boolean; // Whether this is the latest assistant message (for auto-expanding)
 33→  isLastInTurn?: boolean; // Whether this is the last message in its assistant turn
 34→  isWorking?: boolean; // Whether AI is currently working
 35→  isStreamingTurn?: boolean; // Whether this message belongs to the turn currently being generated
 36→}
 37→
 38→export const MessageItem = memo(function MessageItem({
 39→  message,
 40→  isLatestAssistant = false,
 41→  isLastInTurn = false,
 42→  isWorking = false,
 43→  isStreamingTurn = false,
 44→}: MessageItemProps) {
 45→  const { parseContent } = useSession();
 46→  const { copy, copied } = useCopyToClipboard();
 47→  const [isExpanded, setIsExpanded] = useState(false);
 48→  const [shouldCollapse, setShouldCollapse] = useState(false);
 49→  const contentRef = useRef<HTMLDivElement>(null);
 50→
 51→  // Parse message content (memoized to avoid re-parsing JSON on every render)
 52→  const contentBlocks = useMemo(
 53→    () => parseContent(message.content),
 54→    [message.content, parseContent]
 55→  );
 56→
 57→  // Separate image blocks from text/other blocks for grouped rendering (user messages only)
 58→  // Images render in a horizontal row above the collapsible text content
 59→  const { imageBlocks, otherBlocks } = useMemo(() => {
 60→    if (message.role !== "user" || !Array.isArray(contentBlocks)) {
 61→      return { imageBlocks: [] as ContentBlock[], otherBlocks: contentBlocks };
 62→    }
 63→    const images: ContentBlock[] = [];
 64→    const others: (ContentBlock | string)[] = [];
 65→    for (const block of contentBlocks as (ContentBlock | string)[]) {
 66→      if (isImageBlock(block)) {
 67→        images.push(block);
 68→      } else {
 69→        others.push(block);
 70→      }
 71→    }
 72→    return { imageBlocks: images, otherBlocks: others as ParsedContent };
 73→  }, [message.role, contentBlocks]);
 74→
 75→  const hasTextContent = Array.isArray(otherBlocks)
 76→    ? (otherBlocks as (ContentBlock | string)[]).length > 0
 77→    : otherBlocks != null;
 78→
 79→  // Check if content should be collapsible (user messages only, uses theme constants)
 80→  useEffect(() => {
 81→    if (message.role === "user" && contentRef.current) {
 82→      const actualHeight = contentRef.current.scrollHeight;
 83→      setShouldCollapse(actualHeight > COLLAPSE_MAX_HEIGHT);
 84→    }
 85→  }, [message.role, contentBlocks]);
 86→
 87→  // Extract text content for copy functionality
 88→  const extractTextContent = (): string => {
 89→    if (typeof message.content === "string") return message.content;
 90→    if (Array.isArray(contentBlocks)) {
 91→      return contentBlocks
 92→        .map((block: ContentBlock | string) => {
 93→          if (typeof block === "string") return block;
 94→          if (isTextBlock(block)) return block.text;
 95→          return "";
 96→        })
 97→        .join("\n");
 98→    }
 99→    return String(message.content);
100→  };
101→
102→  const handleCopy = () => {
103→    copy(extractTextContent());
104→  };
105→
106→  // Helper: Render content blocks with proper keys (DRY - used for both user/assistant)
107→  const renderContentBlocks = (blocks: (ContentBlock | string)[]) => {
108→    return blocks.map((block: ContentBlock | string, index: number) => {
109→      // Generate unique key: use tool_use id if available, otherwise fallback to index
110→      const key = isToolUseBlock(block) ? block.id : `${message.id}:${index}`;
111→
112→      // A text block is "streaming" when it is the last text block in the last
113→      // message of the actively-streaming turn. Everything else = full opacity.
114→      const isBlockStreaming = isStreamingTurn && isLastInTurn && index === lastTextBlockIndex;
115→
116→      return (
117→        <BlockRenderer
118→          key={key}
119→          block={block}
120→          index={index}
121→          role={message.role}
122→          isStreaming={isBlockStreaming}
123→        />
124→      );
125→    });
126→  };
127→
128→  /**
129→   * MESSAGE FILTERING NOTE
130→   *
131→   * Filtering is now handled in Chat.tsx before messages reach this component.
132→   * Messages with only tool_result blocks or empty content are filtered out upstream.
133→   * This ensures we don't create wrapper divs with incorrect margins for empty messages.
134→   *
135→   * WHY: In Claude's message format, tool_result blocks are not rendered as standalone messages.
136→   * Instead, they are linked to their corresponding tool_use blocks via the toolResultMap.
137→   * See BlockRenderer.tsx for how tool_use blocks retrieve and display their results.
138→   *
139→   * ARCHITECTURE: This follows the BlockRenderer pattern where:
140→   * 1. tool_use blocks are rendered with their input parameters
141→   * 2. tool_result blocks are fetched via toolResultMap and displayed inline with tool_use
142→   * 3. Messages with only tool_result are filtered in Chat.tsx (won't reach this component)
143→   *
144→   * If you see messages not displaying, check:
145→   * 1. Chat.tsx - ensure filtering logic is correct
146→   * 2. BlockRenderer.tsx - ensure tool_use blocks fetch results from toolResultMap
147→   * 3. session.queries.ts - ensure toolResultMap is built correctly
148→   * 4. Backend API - ensure messages have correct content structure
149→   */
150→
151→  // Determine role-based styling
152→  const roleStyles =
153→    message.role === "user"
154→      ? {
155→          container:
156→            "ml-auto w-fit bg-accent hover:bg-accent/80 backdrop-blur-sm transition-colors duration-200 ease-out motion-reduce:transition-none",
157→          text: "font-normal",
158→          textColor: "text-foreground",
159→          maxWidth: "max-w-[85%]",
160→          shape: "rounded-xl",
161→          padding: "px-3 py-2",
162→        }
163→      : { container: "mr-auto", maxWidth: "max-w-full" };
164→
165→  // Find last text block index — used to identify which block is actively streaming.
166→  // Only the last text block in the last message of the streaming turn gets dimmed.
167→  let lastTextBlockIndex = -1;
168→  if (Array.isArray(contentBlocks) && message.role === "assistant") {
169→    const blocks = contentBlocks as (ContentBlock | string)[];
170→    for (let i = blocks.length - 1; i >= 0; i--) {
171→      const block = blocks[i];
172→      if (typeof block === "string" || isTextBlock(block)) {
173→        lastTextBlockIndex = i;
174→        break;
175→      }
176→    }
177→  }
178→
179→  // Group consecutive read-only tool blocks for compact rendering.
180→  // During streaming, trailing streaks render individually (isSealed=false).
181→  // When text follows or the turn completes, they collapse into a header.
182→  const groupedBlocks = useMemo(() => {
183→    if (message.role !== "assistant" || !Array.isArray(contentBlocks)) return null;
184→    return groupToolStreaks(contentBlocks as (ContentBlock | string)[]);
185→  }, [message.role, contentBlocks]);
186→
187→  // Assistant messages - grouped tool streaks + individual blocks
188→  if (message.role === "assistant") {
189→    return (
190→      <div
191→        key={message.id}
192→        className={cn(
193→          "group relative",
194→          roleStyles.maxWidth,
195→          roleStyles.container,
196→          "flex min-w-0 flex-col gap-2 overflow-x-hidden",
197→          "transition-colors duration-100 ease-in motion-reduce:transition-none"
198→        )}
199→      >
200→        {groupedBlocks ? (
201→          groupedBlocks.map((item: GroupedItem) =>
202→            match(item)
203→              .with({ kind: "single" }, (s) => {
204→                const { block, originalIndex } = s;
205→                const key = isToolUseBlock(block) ? block.id : `${message.id}:${originalIndex}`;
206→                const isBlockStreaming =
207→                  isStreamingTurn && isLastInTurn && originalIndex === lastTextBlockIndex;
208→                return (
209→                  <BlockRenderer
210→                    key={key}
211→                    block={block}
212→                    index={originalIndex}
213→                    role="assistant"
214→                    isStreaming={isBlockStreaming}
215→                  />
216→                );
217→              })
218→              .with({ kind: "streak" }, (s) => {
219→                // Trailing streaks stay open during streaming, collapse when sealed
220→                const isSealed = !s.isTrailing || !(isLatestAssistant && isWorking);
221→                return (
222→                  <ToolGroupBlock key={s.blocks[0].id} blocks={s.blocks} isSealed={isSealed} />
223→                );
224→              })
225→              .exhaustive()
226→          )
227→        ) : (
228→          // Fallback for non-array content
229→          <div className="text-base leading-relaxed">
230→            {typeof contentBlocks === "string"
231→              ? contentBlocks
232→              : JSON.stringify(contentBlocks, null, 2)}
233→          </div>
234→        )}
235→      </div>
236→    );
237→  }
238→
239→  // User messages - iMessage style bubble, aligned right
240→  return (
241→    <div key={message.id} className="group relative flex flex-col items-end">
242→      {/* Message card */}
243→      <div
244→        className={cn(
245→          roleStyles.maxWidth,
246→          roleStyles.container,
247→          "relative rounded-xl",
248→          "px-3 py-2",
249→          "min-w-0"
250→        )}
251→      >
252→        {/* Copy button — top-right inside the bubble, icon-only */}
253→        <div className="pointer-events-none absolute top-1.5 right-1.5 z-10 opacity-0 transition-opacity duration-200 group-focus-within:pointer-events-auto group-focus-within:opacity-100 group-hover:pointer-events-auto group-hover:opacity-100">
254→          <ActionButton
255→            icon={Copy}
256→            label={copied ? "Copied" : "Copy"}
257→            onClick={handleCopy}
258→            active={copied}
259→            showLabel={false}
260→            className="bg-accent/80 rounded-md backdrop-blur-sm"
261→          />
262→        </div>
263→        {/* Image thumbnails — always visible, not affected by collapse */}
264→        {imageBlocks.length > 0 && (
265→          <div className={cn("flex flex-wrap gap-1.5", hasTextContent && "mb-2")}>
266→            {imageBlocks.map((block, idx) => (
267→              <BlockRenderer
268→                key={`${message.id}:img:${idx}`}
269→                block={block}
270→                index={idx}
271→                role="user"
272→              />
273→            ))}
274→          </div>
275→        )}
276→
277→        {/* Text content — collapsible for long messages with animated height */}
278→        {hasTextContent && (
279→          <motion.div
280→            ref={contentRef}
281→            id={`message-content-${message.id}`}
282→            className="relative min-w-0 overflow-hidden"
283→            animate={
284→              shouldCollapse
285→                ? { height: isExpanded ? "auto" : COLLAPSE_MAX_HEIGHT }
286→                : { height: "auto" }
287→            }
288→            initial={false}
289→            transition={{ duration: 0.2, ease: [0.165, 0.84, 0.44, 1] }}
290→          >
291→            {Array.isArray(otherBlocks) ? (
292→              renderContentBlocks(otherBlocks as (ContentBlock | string)[])
293→            ) : (
294→              <div className={cn("text-sm leading-relaxed", roleStyles.text)}>
295→                {typeof otherBlocks === "string"
296→                  ? otherBlocks
297→                  : JSON.stringify(otherBlocks, null, 2)}
298→              </div>
299→            )}
300→
301→            {/* Fade overlay for collapsed state - matches user message bg-accent */}
302→            {shouldCollapse && !isExpanded && (
303→              <div className="from-accent via-accent/60 pointer-events-none absolute right-0 bottom-0 left-0 h-12 bg-gradient-to-t to-transparent" />
304→            )}
305→          </motion.div>
306→        )}
307→
308→        {/* Show more/less button */}
309→        {shouldCollapse && (
310→          <button
311→            type="button"
312→            onClick={() => setIsExpanded(!isExpanded)}
313→            className="text-muted-foreground hover:text-foreground mt-2 flex items-center gap-1 text-xs font-normal transition-colors duration-200"
314→            aria-expanded={isExpanded}
315→            aria-controls={`message-content-${message.id}`}
316→          >
317→            {isExpanded ? (
318→              <>
319→                Show less
320→                <ChevronUp className="h-3 w-3" />
321→              </>
322→            ) : (
323→              <>
324→                Show more
325→                <ChevronDown className="h-3 w-3" />
326→              </>
327→            )}
328→          </button>
329→        )}
330→      </div>
331→    </div>
332→  );
333→});
