  2→import type { Message, SessionStatus } from "@/shared/types";
  3→import type { ContentBlock } from "@/features/session/types";
  4→import { isToolResultBlock } from "@/features/session/types";
  5→import { isCancelledMessage } from "../lib/contentParser";
  6→import { MessageItem } from "./MessageItem";
  7→import { AssistantTurn } from "./AssistantTurn";
  8→import { WorkspaceEmptyState } from "./WorkspaceEmptyState";
  9→import { Skeleton } from "@/components/ui/skeleton";
 10→import { Button } from "@/components/ui/button";
 11→import { ChevronDown, TerminalSquare, MessageSquarePlus } from "lucide-react";
 12→import { cn } from "@/shared/lib/utils";
 13→
 14→import { useWorkingDuration } from "@/shared/hooks";
 15→import { useAutoScroll } from "../hooks";
 16→import { useSession } from "../context";
 17→import { useVirtualizer } from "@tanstack/react-virtual";
 18→import { useCallback, useMemo, useRef, useEffect, useLayoutEffect, useState } from "react";
 19→import { AnimatePresence, m } from "framer-motion";
 20→import { CircularPixelGrid, type CircularPixelGridVariant } from "./CircularPixelGrid";
 21→
 22→const USER_PADDING_CLASS = "pb-8";
 23→const TIGHT_PADDING_CLASS = "pb-1";
 24→
 25→/**
 26→ * Turn Types
 27→ *
 28→ * A turn = consecutive messages with the same role (user or assistant)
 29→ * - UserTurn: Single user message
 30→ * - AssistantTurn: One or more consecutive assistant messages
 31→ */
 32→type UserTurn = {
 33→  type: "user";
 34→  message: Message;
 35→  messageIndex: number;
 36→};
 37→
 38→type AssistantTurnData = {
 39→  type: "assistant";
 40→  messages: Message[];
 41→  firstMessageIndex: number;
 42→  isLatest: boolean;
 43→};
 44→
 45→type Turn = UserTurn | AssistantTurnData;
 46→
 47→/**
 48→ * Calculate spacing classes for turns using PADDING (not margin).
 49→ *
 50→ * Padding is used instead of margin because virtual items are absolutely
 51→ * positioned — margins don't affect layout. Padding is included in
 52→ * getBoundingClientRect().height, so the virtualizer's measureElement
 53→ * captures spacing correctly.
 54→ *
 55→ * Spacing logic:
 56→ * - First turn: Top padding (pt-8 for user, pt-1 for assistant)
 57→ * - User turn after assistant: Generous top padding (pt-8)
 58→ * - User turn after user: No extra padding
 59→ * - Assistant turn: No top padding
 60→ * - Bottom padding: User turns add pb-8, assistant turns add minimal padding
 61→ */
 62→function getTurnSpacingClasses(
 63→  turn: Turn,
 64→  prevTurn: Turn | null,
 65→  nextTurn: Turn | null,
 66→  isFirst: boolean
 67→): string {
 68→  const isUser = turn.type === "user";
 69→
 70→  const topClass = (() => {
 71→    if (isUser) {
 72→      if (isFirst) return "pt-8";
 73→      if (prevTurn?.type === "user") return "pt-0";
 74→      return "pt-8";
 75→    }
 76→
 77→    // Assistant turn
 78→    if (isFirst) return "pt-1";
 79→    return "pt-0";
 80→  })();
 81→
 82→  const bottomClass = (() => {
 83→    if (isUser) {
 84→      return USER_PADDING_CLASS;
 85→    }
 86→
 87→    // Assistant turn
 88→    if (nextTurn?.type === "user") {
 89→      return "pb-0";
 90→    }
 91→
 92→    if (nextTurn) {
 93→      return TIGHT_PADDING_CLASS;
 94→    }
 95→
 96→    return "pb-0";
 97→  })();
 98→
 99→  return cn(topClass, bottomClass);
100→}
101→
102→interface ChatProps {
103→  messages: Message[];
104→  loading: boolean;
105→  sessionStatus: SessionStatus;
106→  errorMessage?: string | null;
107→  /** Structured error category from classifyError (e.g. "auth", "rate_limit") */
108→  errorCategory?: string;
109→  agentType?: string | null;
110→  latestMessageSentAt?: string | null;
111→  onStop?: () => void; // Callback to stop/cancel the session
112→  onOpenLoginTerminal?: () => void;
113→  onRetryInNewChat?: () => void;
114→  hasOlder?: boolean;
115→  loadingOlder?: boolean;
116→  onLoadOlder?: () => void;
117→  workspaceRepoName?: string | null;
118→  workspaceParentBranch?: string | null;
119→  isFirstSession?: boolean;
120→  /** Incremented by SessionPanel when the human clicks Send. */
121→  userSendCount?: number;
122→  className?: string;
123→}
124→
125→export function Chat({
126→  messages,
127→  loading,
128→  sessionStatus,
129→  errorMessage,
130→  errorCategory,
131→  agentType,
132→  latestMessageSentAt,
133→  onOpenLoginTerminal,
134→  onRetryInNewChat,
135→  hasOlder = false,
136→  loadingOlder = false,
137→  onLoadOlder,
138→  workspaceRepoName,
139→  workspaceParentBranch,
140→  isFirstSession,
141→  userSendCount = 0,
142→  className,
143→}: ChatProps) {
144→  const { parseContent, toolResultMap, parentToolUseMap } = useSession();
145→
146→  // Chat owns its scroll behavior entirely — refs, hook, and button.
147→  const messagesContainerRef = useRef<HTMLDivElement>(null);
148→
149→  const { showScrollButton, handleScrollToBottomClick, syncGeometry } = useAutoScroll({
150→    messages,
151→    messagesContainerRef,
152→    userSendCount,
153→  });
154→
155→  // --- Message entrance animation tracking ---
156→  // Counter-based: only the turn at index > maxAnimatedTurnIndex gets the
157→  // entrance animation. Simpler than a Set, immune to unbounded growth,
158→  // and prepended messages automatically skip animation (their indices
159→  // are below the counter).
160→  const maxAnimatedTurnIndex = useRef(-1);
161→  // Pre-seed on first render with turns so initial load doesn't animate.
162→  // Without this, the last historical turn always plays the entrance animation.
163→  // Only seeds when conversation loaded with existing messages — new
164→  // conversations (starting empty) should animate their first turn.
165→  const isFirstTurnsRender = useRef(true);
166→  const initialMessageCount = useRef(messages.length);
167→  // Tracks which turns have started their entrance animation. Keeps the CSS
168→  // class applied across re-renders so streaming updates don't interrupt the
169→  // 400ms chatItemEnter animation mid-play (which causes visible jumps).
170→  const animatedTurnsRef = useRef(new Set<number>());
171→
172→  // ── Load-older cooldown ─────────────────────────────────────────────────
173→  // Ref-based guard prevents rapid re-triggering when collapsed content
174→  // produces too little visual height to push the scroll position away
175→  // from the trigger zone. Cleared via rAF after prepend scroll restoration.
176→  const loadOlderCooldownRef = useRef(false);
177→
178→  // ── Prepend scroll restoration (offset-delta approach) ──────────────────
179→  //
180→  // With virtualization, items are absolutely positioned so DOM queries
181→  // (offsetTop) don't work. Instead, track the virtualizer's getTotalSize()
182→  // before and after prepend. The delta = height added by prepended items.
183→  // scrollTop += delta keeps the visual position stable.
184→  const prevFirstSeqRef = useRef<number | null>(null);
185→  const prevTotalSizeRef = useRef<number | undefined>(undefined);
186→
187→  // ── Scroll-position-based load-older (replaces IntersectionObserver) ────
188→  // Scroll-position math instead of a sentinel div.
189→  // Fires when scrollTop < TRIGGER_DISTANCE and no cooldown/loading active.
190→  // The cooldown ref prevents the infinite loop where collapsed tool groups
191→  // produce too little visual height to push scrollTop above the trigger zone.
192→  useEffect(() => {
193→    const container = messagesContainerRef.current;
194→    if (!container || !hasOlder || !onLoadOlder) return;
195→
196→    const TRIGGER_DISTANCE = 200; // px from top
197→    let ticking = false;
198→
199→    const handleScroll = () => {
200→      if (ticking) return;

200→      if (ticking) return;
201→      ticking = true;
202→      requestAnimationFrame(() => {
203→        ticking = false;
204→        if (loadingOlder || loadOlderCooldownRef.current) return;
205→        if (container.scrollTop < TRIGGER_DISTANCE) {
206→          // Set cooldown synchronously — prevents re-entry before React re-renders.
207→          loadOlderCooldownRef.current = true;
208→          onLoadOlder();
209→        }
210→      });
211→    };
212→
213→    container.addEventListener("scroll", handleScroll, { passive: true });
214→    return () => container.removeEventListener("scroll", handleScroll);
215→  }, [messagesContainerRef, hasOlder, loadingOlder, onLoadOlder]);
216→
217→  // Track working duration
218→  const { formattedDuration } = useWorkingDuration({
219→    status: sessionStatus,
220→    latestMessageSentAt,
221→  });
222→
223→  // Memoize message filtering to avoid re-parsing JSON on every render
224→  const renderableMessages = useMemo(() => {
225→    return messages.filter((message) => {
226→      // Skip subagent messages — they render nested under Task tool blocks
227→      if (parentToolUseMap.has(message.id)) return false;
228→
229→      // Keep cancellation sentinels — they trigger "Response stopped" in AssistantTurn
230→      if (isCancelledMessage(message.content)) return true;
231→
232→      const contentBlocks = parseContent(message.content);
233→      const isArray = Array.isArray(contentBlocks);
234→      const onlyToolResults =
235→        isArray &&
236→        contentBlocks.length > 0 &&
237→        contentBlocks.every((block: ContentBlock | string) => isToolResultBlock(block));
238→      const isEmpty =
239→        (isArray && contentBlocks.length === 0) ||
240→        (!isArray && (contentBlocks == null || String(contentBlocks).trim() === ""));
241→      return !(onlyToolResults || isEmpty);
242→    });
243→  }, [messages, parseContent, parentToolUseMap]);
244→
245→  /**
246→   * Derive agent sub-state from the last content block in the message stream.
247→   * Maps to CircularPixelGrid animation variant:
248→   * - thinking: last block is ThinkingBlock (extended reasoning)
249→   * - generating: last block is TextBlock (streaming text)
250→   * - toolExecuting: last block is ToolUseBlock with no result yet
251→   * - error: last tool result has is_error=true
252→   */
253→  const agentSubState = useMemo((): CircularPixelGridVariant => {
254→    if (sessionStatus !== "working") return "generating";
255→
256→    for (let i = renderableMessages.length - 1; i >= 0; i--) {
257→      const msg = renderableMessages[i];
258→      if (msg.role !== "assistant") continue;
259→
260→      const blocks = parseContent(msg.content);
261→      if (!Array.isArray(blocks) || blocks.length === 0) continue;
262→
263→      const lastBlock = blocks[blocks.length - 1];
264→      if (!lastBlock || typeof lastBlock === "string") return "generating";
265→
266→      return match(lastBlock)
267→        .with({ type: "thinking" }, () => "thinking" as const)
268→        .with({ type: "text" }, () => "generating" as const)
269→        .with({ type: "tool_use" }, (b) => {
270→          const result = toolResultMap.get(b.id);
271→          if (result?.is_error) return "error" as const;
272→          if (!result) return "toolExecuting" as const;
273→          return "generating" as const;
274→        })
275→        .otherwise(() => "generating" as const);
276→    }
277→
278→    return "generating";
279→  }, [sessionStatus, renderableMessages, parseContent, toolResultMap]);
280→
281→  /**
282→   * Group consecutive messages into turns
283→   *
284→   * A turn = consecutive messages with the same role
285→   * - User messages: Each user message is its own turn
286→   * - Assistant messages: Consecutive assistant messages form a single turn
287→   *
288→   * This enables turn-level collapsing (hide intermediate messages, show summary)
289→   */
290→  const turns = useMemo(() => {
291→    const turnList: Turn[] = [];
292→    let currentAssistantTurn: Message[] | null = null;
293→    let firstAssistantIndex = -1;
294→
295→    renderableMessages.forEach((message, index) => {
296→      if (message.role === "assistant") {
297→        // Start or continue assistant turn
298→        if (!currentAssistantTurn) {
299→          currentAssistantTurn = [message];
300→          firstAssistantIndex = index;
301→        } else {
302→          currentAssistantTurn.push(message);
303→        }
304→      } else {
305→        // User message - close any open assistant turn first
306→        if (currentAssistantTurn) {
307→          turnList.push({
308→            type: "assistant",
309→            messages: currentAssistantTurn,
310→            firstMessageIndex: firstAssistantIndex,
311→            isLatest: false, // Will be updated later
312→          });
313→          currentAssistantTurn = null;
314→        }
315→
316→        // Add user turn
317→        turnList.push({
318→          type: "user",
319→          message,
320→          messageIndex: index,
321→        });
322→      }
323→    });
324→
325→    // Close any remaining assistant turn
326→    if (currentAssistantTurn) {
327→      turnList.push({
328→        type: "assistant",
329→        messages: currentAssistantTurn,
330→        firstMessageIndex: firstAssistantIndex,
331→        isLatest: false, // Will be updated later
332→      });
333→    }
334→
335→    // Mark the latest assistant turn — but ONLY if it's the very last turn
336→    // in the conversation (no user message after it). A turn followed by a
337→    // user message is completed and must NOT enter streaming mode. Without
338→    // this guard, the gap between "user sends message" and "first assistant
339→    // response arrives" causes the previous completed turn to re-enter
340→    // streaming mode (expanded, dimmed) because isLatest && isWorking = true.
341→    const lastTurn = turnList[turnList.length - 1];
342→    if (lastTurn?.type === "assistant") {
343→      (lastTurn as AssistantTurnData).isLatest = true;
344→    }
345→
346→    return turnList;
347→  }, [renderableMessages]);
