349→  // Advance maxAnimatedTurnIndex after commit (useEffect runs once per commit,
350→  // not twice in StrictMode). During render, shouldAnimate reads the ref purely.
351→  // Without this separation, StrictMode double-render advances the counter on the
352→  // first invocation, so the second invocation (which produces DOM) never applies
353→  // the chat-item-enter CSS class.
354→  useEffect(() => {
355→    if (isFirstTurnsRender.current && turns.length > 0) {
356→      isFirstTurnsRender.current = false;
357→      // Only suppress entrance animation for turns loaded from DB (existing
358→      // conversation). New conversations (started empty) should animate their
359→      // first turn — skipping the seed lets shouldAnimate fire naturally.
360→      if (initialMessageCount.current > 0) {
361→        maxAnimatedTurnIndex.current = turns.length - 1;
362→      }
363→      return;
364→    }
365→    const newMax = turns.length - 1;
366→    if (newMax > maxAnimatedTurnIndex.current) {
367→      // Mark this turn for animation. The Set ensures the CSS class persists
368→      // across re-renders so the 400ms animation isn't interrupted.
369→      animatedTurnsRef.current.add(newMax);
370→      maxAnimatedTurnIndex.current = newMax;
371→      // Clean up after animation completes (400ms duration + 100ms buffer).
372→      setTimeout(() => animatedTurnsRef.current.delete(newMax), 500);
373→    }
374→  }, [turns.length]);
375→
376→  // Pre-compute spacing for each turn (needed because virtualizer skips
377→  // off-screen items — can't compute spacing from DOM neighbors).
378→  const turnSpacings = useMemo(() => {
379→    return turns.map((turn, i) =>
