389→  // ── Virtualizer ──────────────────────────────────────────────────────────
390→  // Only renders visible turns + overscan buffer. TanStack Virtual v3 uses
391→  // an internal ResizeObserver on each measureElement ref to auto-detect
392→  // height changes from expand/collapse — no manual remeasurement needed.
393→  const estimateSize = useCallback(
394→    (index: number) => {
395→      const turn = turns[index];
396→      if (!turn) return 100;
397→      if (turn.type === "user") return 60;
398→      // Scale estimate with message count — collapsed turns with many hidden
399→      // messages show a compact header + summary, while expanded turns (latest)
400→      // need more space. Prevents positioning glitches during scroll.
401→      const msgCount = turn.messages.length;
402→      if (msgCount <= 1) return 120;
403→      if (msgCount <= 3) return 200;
404→      return 200 + (msgCount - 3) * 40;
405→    },
406→    [turns]
407→  );
408→
409→  const getItemKey = useCallback(
410→    (index: number) => {
411→      const turn = turns[index];
412→      if (!turn) return index;
413→      return turn.type === "user" ? turn.message.id : turn.messages[0].id;
414→    },
415→    [turns]
416→  );
417→
418→  const virtualizer = useVirtualizer({
419→    count: turns.length,
420→    getScrollElement: () => messagesContainerRef.current,
421→    estimateSize,
422→    overscan: 8,
423→    getItemKey,
424→  });
425→
426→  // ── Prepend scroll restoration (offset-delta) ──────────────────────────
427→  // When older messages are prepended, the virtualizer's total size grows
428→  // by the estimated height of the new items. Adding that delta to scrollTop
429→  // keeps the viewport position stable. No DOM queries needed.
430→  useLayoutEffect(() => {
431→    if (!messages.length) return;
432→
433→    const currentFirstSeq = messages[0].seq;
434→    const prevFirstSeq = prevFirstSeqRef.current;
435→
436→    if (prevFirstSeq !== null && currentFirstSeq < prevFirstSeq) {
437→      const newTotalSize = virtualizer.getTotalSize();
438→      const prevTotalSize = prevTotalSizeRef.current;
439→      if (prevTotalSize !== undefined) {
440→        const delta = newTotalSize - prevTotalSize;
441→        const container = messagesContainerRef.current;
442→        if (container && delta > 0) {
443→          container.scrollTop += delta;
444→          syncGeometry();
445→          requestAnimationFrame(() => {
446→            loadOlderCooldownRef.current = false;
447→          });
448→        }
449→      }
450→    }
451→
452→    prevFirstSeqRef.current = currentFirstSeq;
453→    prevTotalSizeRef.current = virtualizer.getTotalSize();
454→  }, [messages, virtualizer, syncGeometry]);
455→
456→  // Calculate indicator margin based on last message role
457→  const indicatorMarginClass = useMemo(() => {
458→    const lastRenderableRole = renderableMessages.length
459→      ? renderableMessages[renderableMessages.length - 1].role
460→      : null;
461→    return lastRenderableRole === "user" ? "mt-0" : "mt-1";
462→  }, [renderableMessages]);
463→
464→  return (
465→    <div className={cn("relative min-h-0 flex-1", className)}>
466→      {/* Scroll container — absolute inset-0 fills the positioning wrapper */}
467→      <div
468→        id="chat-messages"
469→        role="log"
470→        aria-live="polite"
471→        className="absolute inset-0 overflow-x-hidden overflow-y-auto px-3 pt-4 md:px-6 md:pt-6"
472→        ref={messagesContainerRef}
473→      >
474→        {loading ? (
475→          <div className="space-y-4">
476→            <Skeleton className="h-12 w-12 rounded-full" />
477→            <Skeleton className="h-6 w-full" />
478→            <Skeleton className="h-4 w-[90%]" />
479→            <Skeleton className="h-4 w-[80%]" />
480→          </div>
