488→          <>
489→            <div className="flex min-h-0 min-w-0 flex-col pb-32">
490→              {/* Load-older spinner — outside virtualizer, at physical top */}
491→              {hasOlder && loadingOlder && (
492→                <div className="flex h-10 items-center justify-center">
493→                  <div className="bg-muted/50 flex items-center gap-2 rounded-full px-3 py-1.5">
494→                    <div className="border-foreground/20 border-t-foreground/60 h-3.5 w-3.5 animate-spin rounded-full border-2" />
