499→              {/* Virtual container — only visible turns + overscan are in the DOM.

  1→/**
  2→ * useAutoScroll — rAF chase loop for smooth chat auto-scroll.
  3→ *
  4→ * CHASE LOOP: Runs at 60fps when !isPaused.
  5→ *   scrollTop += (target - scrollTop) * CHASE_FACTOR each frame.
  6→ *
  7→ * PAUSE: Detected inside the chase loop itself.
  8→ *   If scrollTop decreased since our last write AND not near bottom → pause.
  9→ *   Works for ALL input methods (wheel, scrollbar, keyboard, touch).
 10→ *
 11→ * RESUME:
 12→ *   - User scrolls back to bottom (scroll event, after cooldown)
 13→ *   - User sends a new message
 14→ *   - User clicks "scroll to bottom" button
 15→ */
 16→
 17→import { useState, useEffect, useCallback, useRef, type RefObject } from "react";
 18→import type { Message } from "@/shared/types";
 19→
 20→// ── Constants ────────────────────────────────────────────────────────────
 21→
 22→const BOTTOM_THRESHOLD = 24;
 23→const PAUSE_COOLDOWN_MS = 500;
 24→const CHASE_FACTOR = 0.25;
 25→const GRACE_FRAMES = 15; // ~250ms — absorbs trackpad inertia after resume
 26→
 27→// ── Debug logging ────────────────────────────────────────────────────────
 28→const DEBUG = false;
 29→const log = (...args: unknown[]) => {
 30→  if (DEBUG) console.log("[autoscroll]", ...args);
 31→};
 32→
 33→// ── Helpers ──────────────────────────────────────────────────────────────
 34→
 35→const reducedMotionQuery =
 36→  typeof window !== "undefined" ? window.matchMedia("(prefers-reduced-motion: reduce)") : null;
 37→
 38→function isAtBottom(el: HTMLElement): boolean {
 39→  return el.scrollTop + el.clientHeight >= el.scrollHeight - BOTTOM_THRESHOLD;
 40→}
 41→
 42→// ── Hook ─────────────────────────────────────────────────────────────────
 43→
 44→interface UseAutoScrollOptions {
 45→  messages: Message[];
 46→  messagesContainerRef: RefObject<HTMLDivElement>;
 47→  /** Incremented by the UI when the human clicks Send. Triggers resume + jump to bottom. */
 48→  userSendCount: number;
 49→}
 50→
 51→export function useAutoScroll({
 52→  messages,
 53→  messagesContainerRef,
 54→  userSendCount,
 55→}: UseAutoScrollOptions) {
 56→  const [showScrollButton, setShowScrollButton] = useState(false);
 57→
 58→  const isPausedRef = useRef(false);
 59→  const pausedAtRef = useRef(0);
 60→  const chaseRafRef = useRef<number | null>(null);
 61→
 62→  const prevMessageCountRef = useRef(messages.length);
 63→  const prevLastMessageIdRef = useRef<string | null>(
 64→    messages.length > 0 ? messages[messages.length - 1].id : null
 65→  );
 66→
 67→  // ── Chase loop ──────────────────────────────────────────────────────
 68→
 69→  const pauseFromLoop = useCallback(() => {
 70→    log("PAUSE (from loop) — user scroll detected");
 71→    isPausedRef.current = true;
 72→    pausedAtRef.current = Date.now();
 73→    setShowScrollButton(true);
 74→  }, []);
 75→
 76→  const startChase = useCallback(() => {
 77→    if (chaseRafRef.current !== null) {
 78→      log("startChase: already running, skip");
 79→      return;
 80→    }
 81→
 82→    log("startChase: starting new chase loop");
 83→
 84→    let idleFrames = 0;
 85→    let lastWrittenScrollTop = -1;
 86→    let graceFrames = GRACE_FRAMES;
 87→    let tickCount = 0;
 88→
 89→    const tick = () => {
 90→      const el = messagesContainerRef.current;
 91→      if (!el || isPausedRef.current) {
 92→        log("tick: exit — el:", !!el, "isPaused:", isPausedRef.current);
 93→        chaseRafRef.current = null;
 94→        return;
 95→      }
 96→
 97→      tickCount++;
 98→
 99→      const scrollTop = el.scrollTop;
100→      const scrollHeight = el.scrollHeight;
101→      const clientHeight = el.clientHeight;
102→      const target = scrollHeight - clientHeight;
103→      const distance = target - scrollTop;
104→
105→      // Log every 30th tick to avoid spam, but always log key events
106→      const shouldLogTick = tickCount % 30 === 1;
107→
108→      // ── In-loop pause detection ──────────────────────────────────
109→      if (graceFrames > 0) {
110→        graceFrames--;
111→        if (shouldLogTick) {
112→          log(
113→            `tick ${tickCount}: grace=${graceFrames}, scrollTop=${Math.round(scrollTop)}, lastWritten=${Math.round(lastWrittenScrollTop)}, distance=${Math.round(distance)}`
114→          );
115→        }
116→      } else if (lastWrittenScrollTop >= 0) {
117→        const wentBackward = scrollTop < lastWrittenScrollTop - 2;
118→        const nearBottom = scrollTop + clientHeight >= scrollHeight - 5;
119→
120→        if (wentBackward) {
121→          log(
122→            `tick ${tickCount}: BACKWARD DETECTED — scrollTop=${Math.round(scrollTop)}, lastWritten=${Math.round(lastWrittenScrollTop)}, delta=${Math.round(scrollTop - lastWrittenScrollTop)}, nearBottom=${nearBottom}`
123→          );
124→          if (!nearBottom) {
125→            log(`tick ${tickCount}: → PAUSING (not near bottom)`);
126→            pauseFromLoop();
127→            chaseRafRef.current = null;
128→            return;
129→          } else {
130→            log(`tick ${tickCount}: → ignored (near bottom, likely content shrink)`);
131→          }
132→        } else if (shouldLogTick) {
133→          log(
134→            `tick ${tickCount}: scrollTop=${Math.round(scrollTop)}, lastWritten=${Math.round(lastWrittenScrollTop)}, distance=${Math.round(distance)}, target=${Math.round(target)}`
135→          );
136→        }
137→      }
138→
139→      // ── Chase toward bottom ──────────────────────────────────────
140→      // Snap when close enough or when the step is too small to move pixels
141→      if (distance < 1) {
142→        if (distance > 0) el.scrollTop = target;
143→        if (++idleFrames >= 10) {
144→          log(`tick ${tickCount}: idle self-stop (10 idle frames)`);
145→          chaseRafRef.current = null;
146→          return;
147→        }
148→        lastWrittenScrollTop = el.scrollTop;
149→        chaseRafRef.current = requestAnimationFrame(tick);
150→        return;
151→      }
152→
153→      if (reducedMotionQuery?.matches) {
154→        el.scrollTop = target;
155→      } else {
156→        const prev = el.scrollTop;
157→        el.scrollTop += distance * CHASE_FACTOR;
158→        // Browser rounds scrollTop — if the write didn't actually move, snap
159→        if (el.scrollTop === prev) {
160→          el.scrollTop = target;
161→        }
162→      }
163→
164→      // Count as idle if scroll position didn't change (already at target)
165→      if (el.scrollTop === lastWrittenScrollTop) {
166→        if (++idleFrames >= 10) {
167→          log(`tick ${tickCount}: idle self-stop (stalled)`);
168→          chaseRafRef.current = null;
169→          return;
170→        }
171→      } else {
172→        idleFrames = 0;
173→      }
174→
175→      lastWrittenScrollTop = el.scrollTop;
176→      chaseRafRef.current = requestAnimationFrame(tick);
177→    };
178→
179→    chaseRafRef.current = requestAnimationFrame(tick);
180→  }, [messagesContainerRef, pauseFromLoop]);
181→
182→  const stopChase = useCallback(() => {
183→    if (chaseRafRef.current !== null) {
184→      log("stopChase: cancelling rAF");
185→      cancelAnimationFrame(chaseRafRef.current);
186→      chaseRafRef.current = null;
187→    }
188→  }, []);
189→
190→  // ── Resume ──────────────────────────────────────────────────────────
191→
192→  const resume = useCallback(() => {
193→    log("RESUME — isPaused was:", isPausedRef.current);
194→    isPausedRef.current = false;
195→    setShowScrollButton(false);
196→    stopChase();
197→    startChase();
198→  }, [startChase, stopChase]);
199→
200→  // ── Scroll to bottom ───────────────────────────────────────────────
201→
202→  const scrollToBottom = useCallback(() => {
203→    log("scrollToBottom clicked");
204→    resume();
205→  }, [resume]);
206→
207→  const syncGeometry = useCallback(() => {
208→    log("syncGeometry: pausing chase for 2 frames");
209→    stopChase();
210→    requestAnimationFrame(() => {
211→      requestAnimationFrame(() => {
212→        if (!isPausedRef.current) startChase();
213→      });
214→    });
215→  }, [stopChase, startChase]);
216→
217→  // ── Scroll listener: pause detection + re-engagement ────────────────
218→  useEffect(() => {
219→    const container = messagesContainerRef.current;
220→    if (!container) return;
221→
222→    const handleScroll = () => {
223→      if (!isPausedRef.current) {
224→        // Chase loop may have self-stopped (idle at bottom). If the user
225→        // then scrolls away from bottom, we must pause NOW — otherwise
226→        // the next message arrival will restart the chase and yank them
227→        // back to the bottom. The in-loop backward detection only works
228→        // while the loop is running; this covers the stopped-loop gap.
229→        if (chaseRafRef.current === null && !isAtBottom(container)) {
230→          log("scroll listener: chase idle + scrolled away → PAUSE");
231→          isPausedRef.current = true;
232→          pausedAtRef.current = Date.now();
233→          setShowScrollButton(true);
234→        }
235→        return;
236→      }
237→
238→      // Already paused — check for re-engagement (scroll back to bottom)
239→      const elapsed = Date.now() - pausedAtRef.current;
240→      if (elapsed >= PAUSE_COOLDOWN_MS && isAtBottom(container)) {
241→        log(`scroll re-engagement: at bottom after ${elapsed}ms cooldown`);
242→        resume();
243→      }
244→    };
245→
246→    container.addEventListener("scroll", handleScroll, { passive: true });
247→    return () => container.removeEventListener("scroll", handleScroll);
248→  }, [messagesContainerRef, resume]);
249→
250→  // ── Start chase when content is present ─────────────────────────────
251→  const contentReady = messages.length > 0;
252→  useEffect(() => {
253→    if (!contentReady || isPausedRef.current) return;
254→    log("contentReady effect: starting chase");
255→    startChase();
256→    return () => stopChase();
257→  }, [contentReady, startChase, stopChase]);
258→
259→  // ── Human send → resume ────────────────────────────────────────────
260→  // Triggered by SessionPanel incrementing userSendCount when the human
261→  // actually clicks Send. NOT triggered by agent-server tool_results (which
262→  // also have role="user" in the Claude SDK format).
263→  const prevSendCountRef = useRef(userSendCount);
264→  useEffect(() => {
265→    if (userSendCount === prevSendCountRef.current) return;
266→    prevSendCountRef.current = userSendCount;
267→
268→    log("userSendCount changed — human sent a message");
269→    const container = messagesContainerRef.current;
270→    if (container) {
271→      container.scrollTop = container.scrollHeight;
272→    }
273→    resume();
274→  }, [userSendCount, messagesContainerRef, resume]);
275→
276→  // ── New message handling ────────────────────────────────────────────
277→  // Never resumes — only restarts chase when not paused.
278→  // Resume is handled exclusively by: human send, scroll-to-bottom click,
279→  // or scroll re-engagement (scrolling back to bottom).
280→  useEffect(() => {
281→    const count = messages.length;
282→    const prevCount = prevMessageCountRef.current;
283→    const lastId = count > 0 ? messages[count - 1].id : null;
284→    const prevLastId = prevLastMessageIdRef.current;
285→
286→    prevMessageCountRef.current = count;
287→    prevLastMessageIdRef.current = lastId;
288→
289→    if (count <= prevCount) return;
290→    if (lastId === prevLastId) {
291→      log("message effect: prepend detected, ignoring");
292→      return;
293→    }
294→
295→    const delta = count - prevCount;
296→    log(
297→      `message effect: count ${prevCount}→${count} (delta=${delta}), isPaused=${isPausedRef.current}`
298→    );
299→
300→    if (!isPausedRef.current) {
301→      log("message effect: restarting chase");
302→      stopChase();
303→      startChase();
304→    } else {
305→      log("message effect: paused — ignoring");
306→    }
307→  }, [messages, startChase, stopChase]);
308→
309→  // ── Cleanup ─────────────────────────────────────────────────────────
310→  useEffect(() => () => stopChase(), [stopChase]);
311→
312→  return {
313→    showScrollButton,
314→    handleScrollToBottomClick: scrollToBottom,
315→    syncGeometry,
316→  };
317→}
