  1→/**
  2→ * CircularPixelGrid — Canvas-based high-resolution pixel grid inside a circle.
  3→ *
  4→ * Redesign of the 3×3 PixelGrid: same 6 variants, but rendered at 8–32×
  5→ * resolution inside a circular mask. Uses <canvas> + requestAnimationFrame
  6→ * for smooth 60fps with hundreds of cells.
  7→ *
  8→ * Each variant maps (cell position, time) → opacity, producing:
  9→ *   thinking      : radial breathing (blue)  — center bright, outer subtle
 10→ *   generating    : random sparkle (green)   — organic twinkling sphere
 11→ *   toolExecuting : clockwise sweep (amber)  — radar-scan with tail
 12→ *   error         : cross pulse (red)        — axis-aligned + pattern
 13→ *   compacting    : ring collapse (violet)   — concentric rings inward
 14→ *   working       : shimmer waves (gray)     — sidebar ambient indicator
 15→ */
 16→
 17→import { useRef, useEffect, useMemo, useState } from "react";
 18→import { cn } from "@/shared/lib/utils";
 19→
 20→export type CircularPixelGridVariant =
 21→  | "thinking"
 22→  | "generating"
 23→  | "toolExecuting"
 24→  | "error"
 25→  | "compacting"
 26→  | "working";
 27→
 28→interface CircularPixelGridProps {
 29→  variant: CircularPixelGridVariant;
 30→  /** Total diameter in CSS px (default 24) */
 31→  size?: number;
 32→  /** Grid cells per axis — 8 to 32 (default 16) */
 33→  resolution?: number;
 34→  /** Gap between cells as fraction of cell size [0, 1) (default 0.2) */
 35→  gap?: number;
 36→  /** "square" pixels or "round" dots (default "square") */
 37→  dotShape?: "square" | "round";
 38→  /** Override color — CSS color string (e.g. "oklch(0.65 0.15 265)").
 39→   *  When set, bypasses the variant's CSS variable. */
 40→  color?: string;
 41→  className?: string;
 42→}
 43→
 44→/* ── Variant colors ───────────────────────────────────────── */
 45→
 46→const VARIANT_COLORS: Record<CircularPixelGridVariant, { cssVar: string }> = {
 47→  thinking: { cssVar: "--status-thinking-indicator" },
 48→  generating: { cssVar: "--success" },
 49→  toolExecuting: { cssVar: "--warning" },
 50→  error: { cssVar: "--destructive" },
 51→  compacting: { cssVar: "--status-compacting-indicator" },
 52→  working: { cssVar: "--muted-foreground" },
 53→};
 54→
 55→/* ── Pre-computed cell metadata ────────────────────────────── */
 56→
 57→interface Cell {
 58→  col: number;
 59→  row: number;
 60→  /** Normalized x from center [-1, 1] */
 61→  nx: number;
 62→  /** Normalized y from center [-1, 1] */
 63→  ny: number;
 64→  /** Distance from center [0, 1] */
 65→  dist: number;
 66→  /** Angle from center (radians) */
 67→  angle: number;
 68→  /** Deterministic pseudo-random [0, 1] */
 69→  seed: number;
 70→}
 71→
 72→function buildCells(res: number): Cell[] {
 73→  const out: Cell[] = [];
 74→  const half = res / 2;
 75→  for (let r = 0; r < res; r++) {
 76→    for (let c = 0; c < res; c++) {
 77→      const nx = (c + 0.5 - half) / half;
 78→      const ny = (r + 0.5 - half) / half;
 79→      const dist = Math.sqrt(nx * nx + ny * ny);
 80→      if (dist <= 1.0) {
 81→        out.push({
 82→          col: c,
 83→          row: r,
 84→          nx,
 85→          ny,
 86→          dist,
 87→          angle: Math.atan2(ny, nx),
 88→          seed: ((c * 7919 + r * 6271 + c * r * 31) % 997) / 997,
 89→        });
 90→      }
 91→    }
 92→  }
 93→  return out;
 94→}
 95→
 96→/* ── Animation functions: (cell, time) → opacity [0, 1] ──── */
 97→
 98→function thinkingOp(c: Cell, t: number): number {
 99→  const { dist, angle, seed } = c;
100→
101→  // Rotating bright zone sweeps around the circle (~2.5s per revolution)
102→  const rotAngle = t * 0.4 * Math.PI * 2;
103→  let aDiff = angle - rotAngle;
104→  if (aDiff > Math.PI) aDiff -= Math.PI * 2;
105→  if (aDiff < -Math.PI) aDiff += Math.PI * 2;
106→  const rotWave = Math.pow((Math.cos(aDiff * 1.2) + 1) / 2, 0.8);
107→
108→  // Radial pulse emanating outward from center (faster, ~1.2s cycle)
109→  const ripple = (Math.sin(t * 0.85 * Math.PI * 2 - dist * Math.PI * 2) + 1) / 2;
110→
111→  // Combine: rotation gives sweeping shape, ripple gives radial energy
112→  const combined = rotWave * 0.55 + ripple * 0.45;
113→
114→  // Center stays brighter, outer ring more dramatic contrast
115→  const distFactor = 0.4 + (1 - dist) * 0.6;
116→
117→  // Per-cell flicker for "neural" feel
118→  const flicker = 0.85 + seed * 0.15;
119→
120→  return combined * distFactor * flicker;
121→}
122→
123→function generatingOp(c: Cell, t: number): number {
124→  const { seed, dist } = c;
125→
126→  const freq = 0.25 + seed * 0.8;
127→  const phase = seed * Math.PI * 9.3;
128→  const raw = Math.sin(t * freq * Math.PI * 2 + phase);
129→  // Cube the positive half for sharp sparkle peaks
130→  const sparkle = Math.pow(Math.max(0, raw), 3);
131→
132→  return sparkle * (0.65 + (1 - dist) * 0.35);
133→}
