136→  const { angle, dist } = c;
137→
138→  // Clockwise sweep with a trailing tail
139→  const sweep = ((t * Math.PI * 2) / 2.4) % (Math.PI * 2);
140→  let diff = angle - sweep;
141→  if (diff > Math.PI) diff -= Math.PI * 2;
142→  if (diff < -Math.PI) diff += Math.PI * 2;
143→
144→  const leading = 0.5;
145→  const trailing = 1.4;
146→  let intensity: number;
147→  if (diff >= 0 && diff < leading) {
148→    intensity = 1 - diff / leading;
149→  } else if (diff < 0 && diff > -trailing) {
