  --accent-red: var(--destructive);
  --accent-red-muted: color-mix(in oklch, var(--destructive) 50%, var(--muted-foreground));
  --accent-gold: var(--warning);

  /* --- Neutral scale (pure gray ramp) --- */
  --neutral-50: #e0e0e0;
  --neutral-100: #c8c8c8;
  --neutral-200: #a0a0a0;
  --neutral-300: #909090;
  --neutral-400: #808080;
  --neutral-500: #686868;
  --neutral-600: #555555;
  --neutral-700: #404040;
  --neutral-800: #2a2a2a;
